mapper.select:
select s.Schedule_ID as scheduleId, cl.Class_Name as className, t.Teacher_Name as teacherName, c.Course_Name as courseName, cr.Classroom_Name as classroomName, s.Schedule_Weekday as weekday, s.Schedule_Section as section, s.Schedule_Week as week, c.Course_SingleHour as courseSingleHour from schedule s left join class cl on s.Schedule_Class_ID = cl.Class_ID left join teacher t on s.Schedule_Teacher_ID = t.Teacher_ID left join course c on s.Schedule_Course_ID = c.Course_ID left join classroom cr on s.Schedule_Classroom_ID = cr.Classroom_ID
and #{week} between c.Course_StartWeek and c.Course_EndWeek
and s.Schedule_Class_ID = #{classId}
and s.Schedule_Teacher_ID = #{teacherId}
order by s.Schedule_Weekday, s.Schedule_Section, s.Schedule_ID
